const raw = $input.first().json;

// If the DB query failed entirely
if (raw.error) {
  return [{ json: { skip: true, message: `DB error: ${raw.error.message || raw.error}` } }];
}

// Parse the JSON blob from Postgres
let d;
try {
  d = typeof raw.data === 'string' ? JSON.parse(raw.data) : raw.data;
} catch (e) {
  return [{ json: { skip: true, message: `Parse error: ${e.message}` } }];
}

if (!d.table_exists) {
  return [{ json: { skip: true, message: 'clearnetwork.mrf_research not found — skipping' } }];
}

const c = d.coverage || {};
if (parseInt(c.total_entries) === 0) {
  return [{ json: { skip: true, message: 'No data in mrf_research' } }];
}

const worst = (d.worst || []).slice(0, 15);
const best = (d.best || []).slice(0, 15);
const failures = d.failures || [];
const darkStates = d.dark_states || [];

const now = new Date();
const dateStr = now.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric', timeZone: 'America/New_York' });
const dateSlug = now.toISOString().split('T')[0];
const pctAuto = Math.floor((parseInt(c.automatable) * 100) / Math.max(parseInt(c.total_entries), 1));

const prompt = `You are ClearNetwork, an automated healthcare transparency reporter. Generate a blog post in markdown for ${dateStr}.

DATA:
- Total insurer-state entries: ${c.total_entries}
- Unique insurers: ${c.unique_insurers}
- States covered: ${c.states}
- Automatable (compliant): ${c.automatable} (${pctAuto}%)
- Browser-required: ${c.browser_required}
- Dead links: ${c.dead}
- Auth-blocked: ${c.auth_blocked}
- Avg transparency score: ${c.avg_transparency}/100
- Avg digital debt score: ${c.avg_debt}/100
- Successfully crawled: ${c.successfully_crawled}

WORST OFFENDERS (by digital debt score):
${worst.map((w, i) => `${i+1}. ${w.insurer_name} (${w.state}) - Debt: ${w.digital_debt_score}/100 - ${w.accessibility} - ${w.notes || ''}`).join('\n')}

BEST PERFORMERS (by transparency score):
${best.map((b, i) => `${i+1}. ${b.insurer_name} (${b.state}) - Score: ${b.transparency_score}/100 - ${b.index_type || 'unknown'}`).join('\n')}

DARK STATES (zero automatable): ${darkStates.length > 0 ? darkStates.join(', ') : 'None'}

RECENT CRAWL FAILURES:
${failures.map(f => `- ${f.insurer_name}: ${(f.error_message || 'Unknown').substring(0, 100)}`).join('\n') || 'None'}

Generate a complete markdown blog post with:
1. Dynamic title reflecting today's findings
2. Summary blockquote
3. "The Numbers" table
4. "Digital Debt Hall of Shame" (top 15)
5. Spotlight on #1 worst offender
6. "Transparency Leaders" (top 10)
7. "Dark States" if any
8. "Crawl Struggles" if failures exist
9. "Why This Matters"
10. Auto-generation footer by ClearNetwork

Tone: investigative journalism, data-driven, holding insurers accountable.`;

return [{ json: { skip: false, prompt, coverage: c, dateStr, dateSlug, pctAuto } }];

const response = $input.first().json;
const prev = $('Build Prompt').first().json;
const c = prev.coverage;

let markdown = (response.content && response.content[0]) ? response.content[0].text : '';

const titleMatch = markdown.match(/^#\s+(.+)$/m);
const title = titleMatch ? titleMatch[1] : `Transparency Report — ${prev.dateStr}`;
const summary = `We scanned ${c.unique_insurers} health insurers across ${c.states} states. Only ${c.automatable} (${prev.pctAuto}%) make their pricing data machine-readable.`;

function mdToHtml(md) {
  const lines = md.split('\n'), html = [];
  let inTable = false;
  for (const line of lines) {
    const s = line.trim();
    if (s.startsWith('# ')) html.push(`<h1 style="color:#3b82f6;font-size:24px;margin-bottom:8px">${s.slice(2)}</h1>`);
    else if (s.startsWith('## ')) html.push(`<h2 style="color:#60a5fa;font-size:14px;margin-top:32px;text-transform:uppercase;letter-spacing:1px">${s.slice(3)}</h2>`);
    else if (s.startsWith('### ')) html.push(`<h3 style="color:#e4e4e7;font-size:16px;margin-top:16px">${s.slice(4)}</h3>`);
    else if (s.startsWith('> ')) html.push(`<blockquote style="border-left:3px solid #3b82f6;padding-left:16px;color:#a1a1aa;font-style:italic;margin:16px 0">${s.slice(2)}</blockquote>`);
    else if (s.startsWith('|')) {
      if (!inTable) { html.push('<table style="width:100%;border-collapse:collapse;font-size:13px;margin:12px 0">'); inTable = true; }
      if (/^\|[\s-:]+\|/.test(s)) continue;
      const cells = s.split('|').slice(1,-1).map(c => c.trim());
      html.push(`<tr>${cells.map(c => `<td style="padding:6px 10px;border-bottom:1px solid #2a2a2d">${c}</td>`).join('')}</tr>`);
    } else {
      if (inTable) { html.push('</table>'); inTable = false; }
      if (s.startsWith('- ')) html.push(`<li style="margin:4px 0;color:#e4e4e7">${s.slice(2)}</li>`);
      else if (s === '---') html.push('<hr style="border:none;border-top:1px solid #2a2a2d;margin:24px 0">');
      else if (s) {
        let t = s; while (t.includes('**')) t = t.replace('**','<strong>').replace('**','</strong>');
        html.push(`<p style="color:#e4e4e7;line-height:1.6;margin:8px 0">${t}</p>`);
      }
    }
  }
  if (inTable) html.push('</table>');
  return `<div style="font-family:Inter,sans-serif;background:#0c0c0e;color:#e4e4e7;padding:32px;max-width:800px;margin:0 auto">${html.join('\n')}</div>`;
}

return [{ json: { title, slug: `transparency-report-${prev.dateSlug}`, summary, markdown, contentHtml: mdToHtml(markdown), stats: JSON.stringify({total_entries:parseInt(c.total_entries),unique_insurers:parseInt(c.unique_insurers),automatable:parseInt(c.automatable),browser_required:parseInt(c.browser_required),dead:parseInt(c.dead)}) } }];
